<?php
if(!defined("IN_ESOTALK"))exit;class online extends Controller{var $view="online.view.php";function init(){global $language,$config;$this->title=$language["Online members"];$this->esoTalk->addToHead("<meta name='robots' content='noindex, noarchive'/>");$this->online=$this->esoTalk->db->query("SELECT memberId, name, avatarFormat, IF(color>{$this->esoTalk->skin->numberOfColors},{$this->esoTalk->skin->numberOfColors},color), account, lastSeen, lastAction FROM {$config["tablePrefix"]}members WHERE UNIX_TIMESTAMP()-{$config["userOnlineExpire"]}<lastSeen ORDER BY lastSeen DESC");$this->numberOnline=$this->esoTalk->db->numRows($this->online);}}?>
